// JWT Claims Extractor — decode the already-verified JWT payload
// The Webhook node has already verified the signature and expiry.
const authHeader = $json.headers?.authorization || $json.headers?.Authorization || '';
const token = authHeader.replace(/^Bearer\s+/i, '');

if (!token) {
  throw new Error('No JWT token found in Authorization header');
}

// Decode payload (middle part) — no crypto needed, already verified
const payloadB64 = token.split('.')[1];
const payload = JSON.parse(Buffer.from(payloadB64, 'base64url').toString('utf8'));

return [{
  json: {
    ...$json,
    jwtClaims: {
      user_id: payload.sub || payload.user_id,
      username: payload.username,
      role: payload.role
    }
  }
}];

const body = $json.body || {};
const messages = body.messages || [];
const userMsg = [...messages].reverse().find(m => m.role === 'user');

if (!userMsg || !userMsg.content || userMsg.content.trim().length === 0) {
  return [{ json: { __error: true, errorMsg: 'Leere Eingabe. Bitte gib etwas ein.', allMessages: messages } }];
}

// user_id comes from JWT claims — body.user_id is ignored
const userId = $json.jwtClaims?.user_id;
const username = $json.jwtClaims?.username;
const role = $json.jwtClaims?.role;
const sessionId = body.session_id || require('crypto').randomUUID();

return [{
  json: {
    __error: false,
    userMessage: userMsg.content.trim(),
    userId,
    username,
    role,
    sessionId,
    allMessages: messages,
    requestStartMs: Date.now()
  }
}];

const errorMsg = $json.errorMsg || 'Ungültige Eingabe.';
const now = Math.floor(Date.now() / 1000);
return [{ json: {
  id: 'chatcmpl-err-' + now.toString(36),
  object: 'chat.completion',
  created: now,
  model: 'alice',
  choices: [{ index: 0, message: { role: 'assistant', content: errorMsg }, finish_reason: 'stop' }],
  usage: { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 }
}}];

const text = $('Input Validator').first().json.userMessage || '';
const SPLITTERS = ['und dann', 'und danach', 'und außerdem', 'und', 'dann', 'danach', 'außerdem', 'sowie', 'zusätzlich', 'auch noch'];
const FILLER = /^(bitte|mal|noch|auch|doch|kurz)\s+/gi;
const PUNCT = /[,\.;]+/;

function stripFillers(str) {
  let prev = '';
  let result = str;
  while (result !== prev) {
    prev = result;
    result = result.replace(FILLER, '').trim();
  }
  return result;
}

function splitText(input) {
  let parts = [input];
  for (const sep of SPLITTERS) {
    const regex = new RegExp(`\\b${sep}\\b`, 'gi');
    parts = parts.flatMap(p => p.split(regex));
  }
  parts = parts.flatMap(p => p.split(PUNCT));
  return parts
    .map(p => stripFillers(p))
    .filter(p => p.length >= 4);
}

const parts = splitText(text);
return [{ json: { ...($json), parts: parts.length > 0 ? parts : [text] } }];

const latencyMs = Date.now() - ($json.requestStartMs || Date.now());
const toolResults = {
  path_taken: 'HA_FAST',
  intents_matched: $json.intentResults ? $json.intentResults.filter(r => r.matched).map(r => r.intentTemplate) : [],
  certainty_scores: $json.intentResults ? $json.intentResults.filter(r => r.matched).map(r => r.certainty) : [],
  ha_results: $json.haResults ? $json.haResults.map(r => ({ entity: r.intent ? r.intent.entityId : null, success: r.success, error: r.error })) : [],
  latency_ms: latencyMs,
  confirmation_required: $json.__confirmationRequired || false
};
const userMessageRow = {
  session_id: $json.sessionId,
  user_id: $json.userId,
  role: 'user',
  content: $json.userMessage,
  tool_calls: null,
  tool_results: null
};
return [{ json: { ...($json), toolResults, latencyMs, userMessageRow } }];

const now = Math.floor(Date.now() / 1000);
const text = $json.responseText || 'Erledigt.';
return [{ json: {
  id: 'chatcmpl-ha-' + now.toString(36),
  object: 'chat.completion',
  created: now,
  model: 'alice-ha-fast',
  choices: [{ index: 0, message: { role: 'assistant', content: text }, finish_reason: 'stop' }],
  usage: { prompt_tokens: 0, completion_tokens: text.length, total_tokens: text.length }
}}];

const latencyMs = Date.now() - ($json.requestStartMs || Date.now());
const toolResults = {
  path_taken: 'HYBRID',
  intents_matched: $json.intentResults ? $json.intentResults.filter(r => r.matched).map(r => r.intentTemplate) : [],
  certainty_scores: $json.intentResults ? $json.intentResults.filter(r => r.matched).map(r => r.certainty) : [],
  ha_results: $json.haResults ? $json.haResults.map(r => ({ entity: r.intent ? r.intent.entityId : null, success: r.success, error: r.error })) : [],
  llm_used: true,
  latency_ms: latencyMs
};
const userMessageRow = {
  session_id: $json.sessionId,
  user_id: $json.userId,
  role: 'user',
  content: $json.userMessage,
  tool_calls: null,
  tool_results: null
};
return [{ json: { ...($json), toolResults, latencyMs, userMessageRow } }];

const now = Math.floor(Date.now() / 1000);
const text = $json.responseText || 'Erledigt.';
return [{ json: {
  id: 'chatcmpl-hy-' + now.toString(36),
  object: 'chat.completion',
  created: now,
  model: 'alice-hybrid',
  choices: [{ index: 0, message: { role: 'assistant', content: text }, finish_reason: 'stop' }],
  usage: { prompt_tokens: 0, completion_tokens: text.length, total_tokens: text.length }
}}];

return [{ json: {
  chatInput: $json.userMessage,
  body: {
    messages: $json.allMessages,
    user_id: $json.userId,
    session_id: $json.sessionId
  },
  __pathDecision: 'LLM_ONLY',
  __requestStartMs: $json.requestStartMs,
  __userId: $json.userId,
  __sessionId: $json.sessionId
}}];

const startMs = $('LLM Only Prep').first().json.__requestStartMs || Date.now();
const latencyMs = Date.now() - startMs;
const toolResults = { path_taken: 'LLM_ONLY', latency_ms: latencyMs, llm_used: true };
const text = $json.output || $json.text || $json.completion || $json.answer || $json.response || '';
const userMessageRow = {
  session_id: $('LLM Only Prep').first().json.__sessionId,
  user_id: $('LLM Only Prep').first().json.__userId,
  role: 'user',
  content: $('Input Validator').first().json.userMessage,
  tool_calls: null,
  tool_results: null
};
return [{ json: {
  ...($json),
  __responseText: text,
  __toolResults: toolResults,
  __userId: $('LLM Only Prep').first().json.__userId,
  __sessionId: $('LLM Only Prep').first().json.__sessionId,
  __userMessageRow: userMessageRow
}}];

const now = Math.floor(Date.now() / 1000);
const text = $json.__responseText || $json.output || $json.text || $json.completion || $json.answer || $json.response || '';
return [{ json: {
  id: 'chatcmpl-' + now.toString(36),
  object: 'chat.completion',
  created: now,
  model: 'alice-llm',
  choices: [{ index: 0, message: { role: 'assistant', content: text }, finish_reason: 'stop' }],
  usage: { prompt_tokens: 0, completion_tokens: (text||'').length, total_tokens: (text||'').length }
}}];

const parts = $json.parts || [$json.userMessage];
return parts.map(currentPart => ({
  json: { ...$json, currentPart }
}));

// Filter & Rank (Run Once for Each Item)
// IMPORTANT: must return a single item object: { json: {...} }  (NOT an array)

const CONFIRMATION_DOMAINS = ['lock', 'alarm_control_panel'];
const CERTAINTY_THRESHOLD = (typeof $json.intentMinCertainty === 'number')
  ? $json.intentMinCertainty
  : 0.82;

const candidates = $json?.data?.Get?.HAIntent ?? [];

const qualified = candidates
  .filter(c => (c?._additional?.certainty || 0) >= CERTAINTY_THRESHOLD)
  .sort((a, b) => (b?._additional?.certainty || 0) - (a?._additional?.certainty || 0));

const best = qualified[0];

function safeParseParams(p) {
  if (!p) return {};
  if (typeof p === 'object' && !Array.isArray(p)) return p;
  if (typeof p === 'string') {
    try {
      const parsed = JSON.parse(p);
      return (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) ? parsed : {};
    } catch {
      return {};
    }
  }
  return {};
}

// Preserve context if present (from Split Parts / Merge)
const context = {
  weaviateUrl: $json.weaviateUrl,
  intentMinCertainty: $json.intentMinCertainty,
  intentMaxResults: $json.intentMaxResults,
  parts: $json.parts,
  currentPart: $json.currentPart,
  // User context — must be forwarded so Build Route Decision can reconstruct base
  userId: $('Input Validator').item.json.userId,
  sessionId: $('Input Validator').item.json.sessionId,
  userMessage: $json.userMessage,
  allMessages: $json.allMessages,
  requestStartMs: $json.requestStartMs,
  username: $json.username,
  role: $json.role,
};

if (best) {
  return {
    json: {
      ...context,
      matched: true,
      certainty: best._additional?.certainty || 0,
      entityId: best.entityId,
      domain: best.domain,
      service: best.service,
      parameters: safeParseParams(best.parameters),
      intentTemplate: best.intentTemplate,
      requiresConfirmation: CONFIRMATION_DOMAINS.includes(best.domain),
      weaviateError: false,
      weaviateErrorMsg: null,
    }
  };
}

return {
  json: {
    ...context,
    matched: false,
    certainty: candidates[0]?._additional?.certainty || 0,
    weaviateError: false,
    weaviateErrorMsg: null,
  }
};

const all = $input.all();
const totalCount = all.length;

// Take base context from the first incoming item.
// This requires that Split Parts carried those fields through.
const base = all[0]?.json ?? {};

const matchedParts = all.filter(i => i.json.matched);
const matchedCount = matchedParts.length;

const anyWeaviateError = all.some(i => i.json.weaviateError);

// Decision logic
let pathDecision = 'LLM_ONLY';
if (totalCount === 0) {
  pathDecision = 'LLM_ONLY';
} else if (!anyWeaviateError && matchedCount === totalCount && matchedCount > 0) {
  pathDecision = 'HA_FAST';
} else if (matchedCount > 0) {
  pathDecision = 'HYBRID';
} else {
  pathDecision = 'LLM_ONLY';
}

return [{
  json: {
    // --- BASE CONTEXT (must always be present) ---
    userMessage: base.userMessage ?? base.chatInput ?? (base.parts ? base.parts.join('. ') : undefined),
    chatInput: base.chatInput ?? base.userMessage ?? (base.parts ? base.parts.join('. ') : undefined),
    userId: base.userId,
    username: base.username,
    role: base.role,
    sessionId: base.sessionId,
    allMessages: base.allMessages ?? [],
    requestStartMs: base.requestStartMs,

    // --- routing payload ---
    parts: base.parts ?? all.map(i => i.json.currentPart).filter(Boolean),
    pathDecision,
    intentResults: all.map(i => ({
      part: i.json.currentPart ?? i.json.part,
      matched: i.json.matched,
      certainty: i.json.certainty,
      entityId: i.json.entityId,
      domain: i.json.domain,
      service: i.json.service,
      parameters: i.json.parameters,
      intentTemplate: i.json.intentTemplate,
      requiresConfirmation: i.json.requiresConfirmation,
      weaviateError: i.json.weaviateError,
      weaviateErrorMsg: i.json.weaviateErrorMsg
    })),
    matchedCount,
    totalCount,
    anyWeaviateError
  }
}];

// HA Fast - Prep Requests
// Output: one item per HA call request (kind="ha"), or a single validation/noop request (kind="noop")
// Keeps the final output contract expected downstream: haResults, responseText, __confirmationRequired

function normalizeBaseUrl(u) {
  const raw = (u ?? '').toString().trim();
  if (!raw) return null;
  const withScheme = /^[a-zA-Z][a-zA-Z0-9+.-]*:\/\//.test(raw) ? raw : `http://${raw}`;
  return withScheme.replace(/\/+$/, '');
}

const HA_URL = normalizeBaseUrl($env.HA_URL) || 'http://homeassistant:8123';
const HA_TOKEN = ($env.HA_TOKEN ?? '').toString().trim();

const intentResults = $json.intentResults || [];
const intents = intentResults.filter(r => r.matched);

const needsConfirmation = intents.filter(i => i.requiresConfirmation);
const executableIntents = intents.filter(i => !i.requiresConfirmation);

const base = {
  // Keep original payload for downstream nodes
  ...$json,
  __haUrl: HA_URL,
};

if (!HA_TOKEN) {
  // No HTTP call, but we still output one item so the route continues deterministically
  return [{
    json: {
      ...base,
      __confirmationRequired: false,
      __haPrepError: true,
      responseText: 'HA_TOKEN fehlt. Bitte Umgebungsvariable setzen.',
      haResults: [],
      __http: {
        kind: 'noop',
        method: 'GET',
        url: `${HA_URL}/api/`,
        headers: { Authorization: `Bearer ${HA_TOKEN}`, 'Content-Type': 'application/json' },
        body: null,
      },
    }
  }];
}

// Confirmation-only case: don't execute any HA services, but we can still do a harmless GET /api/ to validate connectivity/token
if (executableIntents.length === 0 && needsConfirmation.length > 0) {
  const names = needsConfirmation.map(i => i.entityId || i.domain).join(', ');
  return [{
    json: {
      ...base,
      __confirmationRequired: true,
      haResults: [],
      responseText: `Bist du sicher? Ich soll ${names} steuern. Bitte bestätige mit "Ja".`,
      __http: {
        kind: 'noop',
        method: 'GET',
        url: `${HA_URL}/api/`,
        headers: { Authorization: `Bearer ${HA_TOKEN}`, 'Content-Type': 'application/json' },
        body: null,
      },
    }
  }];
}

// Normal case: create one item per executable intent
return executableIntents.map(intent => {
  const [domain, ...rest] = (intent.service || '').split('.');
  const service = rest.join('.');
  const body = { entity_id: intent.entityId, ...(intent.parameters || {}) };

  return {
    json: {
      ...base,
      __confirmationRequired: needsConfirmation.length > 0,
      __needsConfirmation: needsConfirmation,
      __http: {
        kind: 'ha',
        method: 'POST',
        url: `${HA_URL}/api/services/${domain}/${service}`,
        headers: {
          Authorization: `Bearer ${HA_TOKEN}`,
          'Content-Type': 'application/json',
        },
        body,
      },
      __intent: intent, // keep for assembling results
    }
  };
});

// Hybrid - Prep Requests
// Creates items for:
// - HA calls (kind="ha") for matched executable intents
// - one Ollama call (kind="ollama") if llmParts exist
// - one noop GET /api/ if nothing to do (edge case)

function normalizeBaseUrl(u) {
  const raw = (u ?? '').toString().trim();
  if (!raw) return null;
  const withScheme = /^[a-zA-Z][a-zA-Z0-9+.-]*:\/\//.test(raw) ? raw : `http://${raw}`;
  return withScheme.replace(/\/+$/, '');
}

const HA_URL = normalizeBaseUrl($env.HA_URL) || 'http://homeassistant:8123';
const HA_TOKEN = ($env.HA_TOKEN ?? '').toString().trim();

const OLLAMA_URL = normalizeBaseUrl($env.OLLAMA_URL) || 'http://ollama:11434';
const OLLAMA_MODEL = ($env.OLLAMA_MODEL ?? 'qwen3:14b').toString().trim();

const allIntents = $json.intentResults || [];
const haIntents = allIntents.filter(r => r.matched && !r.requiresConfirmation);
const confirmIntents = allIntents.filter(r => r.matched && r.requiresConfirmation);
const llmParts = allIntents.filter(r => !r.matched).map(r => r.part).filter(Boolean);

const base = {
  ...$json,
  __haUrl: HA_URL,
  __ollamaUrl: OLLAMA_URL,
  __ollamaModel: OLLAMA_MODEL,
  __confirmationRequired: confirmIntents.length > 0,
  __confirmIntents: confirmIntents,
};

const out = [];

// HA items
for (const intent of haIntents) {
  const [domain, ...rest] = (intent.service || '').split('.');
  const service = rest.join('.');
  const body = { entity_id: intent.entityId, ...(intent.parameters || {}) };

  out.push({
    json: {
      ...base,
      __http: {
        kind: 'ha',
        method: 'POST',
        url: `${HA_URL}/api/services/${domain}/${service}`,
        headers: {
          Authorization: `Bearer ${HA_TOKEN}`,
          'Content-Type': 'application/json',
        },
        body,
      },
      __intent: intent,
    }
  });
}

// Ollama item (only if we have non-intent parts)
if (llmParts.length > 0) {
  const userText = llmParts.join('. ');
  out.push({
    json: {
      ...base,
      __http: {
        kind: 'ollama',
        method: 'POST',
        url: `${OLLAMA_URL}/api/chat`,
        headers: { 'Content-Type': 'application/json' },
        body: {
          model: OLLAMA_MODEL,
          messages: [...($json.allMessages || []), { role: 'user', content: userText }],
          stream: false
        }
      }
    }
  });
}

// Edge case: nothing to do -> noop
if (out.length === 0) {
  out.push({
    json: {
      ...base,
      __http: {
        kind: 'noop',
        method: 'GET',
        url: `${HA_URL}/api/`,
        headers: {
          Authorization: `Bearer ${HA_TOKEN}`,
          'Content-Type': 'application/json',
        },
        body: null
      }
    }
  });
}

return out;

// Hybrid - Assemble (for Merge By Position output)
// Expects items that are merged from:
// - Input 1 (Prep): has __http.kind, __intent, __confirmIntents, __confirmationRequired
// - Input 2 (HTTP): has statusCode, body, headers, statusMessage (full response)

const items = $input.all();

function actionText(service) {
  const svc = service || '';
  return svc.includes('turn_on') ? 'eingeschaltet'
    : svc.includes('turn_off') ? 'ausgeschaltet'
    : svc.includes('open') ? 'geöffnet'
    : svc.includes('close') ? 'geschlossen'
    : svc.includes('start') ? 'gestartet'
    : svc.includes('stop') ? 'gestoppt'
    : svc.includes('return') ? 'zurückgeschickt'
    : svc.includes('lock') ? 'gesperrt'
    : svc.includes('unlock') ? 'entsperrt'
    : svc.includes('arm') ? 'scharf geschaltet'
    : svc.includes('disarm') ? 'deaktiviert'
    : svc.includes('set_temperature') ? 'eingestellt'
    : 'ausgeführt';
}

function entityLabel(intent) {
  const raw = (intent?.entityId || intent?.domain || 'Aktion');
  const name = raw.split('.').pop().replace(/_/g, ' ');
  return name.charAt(0).toUpperCase() + name.slice(1);
}

// Because Merge node structures can vary, we extract prep+http data defensively
function getKind(j) {
  // Prefer merged __http.kind if present
  if (j?.__http?.kind) return j.__http.kind;

  // Some merge modes nest inputs; try common patterns
  if (j?.input1?.__http?.kind) return j.input1.__http.kind;
  if (j?.json?.__http?.kind) return j.json.__http.kind;

  return null;
}

function getIntent(j) {
  return j?.__intent || j?.input1?.__intent || null;
}

function getConfirmIntents(base) {
  return base?.__confirmIntents || base?.input1?.__confirmIntents || [];
}

function getConfirmationRequired(base) {
  return !!(base?.__confirmationRequired ?? base?.input1?.__confirmationRequired);
}

function getHttpResponse(j) {
  // HTTP Request node output fields are usually at top-level: statusCode/body/headers
  if (typeof j?.statusCode === 'number') {
    return {
      statusCode: j.statusCode,
      body: j.body,
      statusMessage: j.statusMessage,
      headers: j.headers,
      error: j.error
    };
  }

  // If merge nested it
  if (j?.input2 && typeof j.input2.statusCode === 'number') {
    return {
      statusCode: j.input2.statusCode,
      body: j.input2.body,
      statusMessage: j.input2.statusMessage,
      headers: j.input2.headers,
      error: j.input2.error
    };
  }

  // Some merge nodes may put second stream under another key; last resort:
  const maybe = Object.values(j || {}).find(v => v && typeof v === 'object' && typeof v.statusCode === 'number');
  if (maybe) {
    return {
      statusCode: maybe.statusCode,
      body: maybe.body,
      statusMessage: maybe.statusMessage,
      headers: maybe.headers,
      error: maybe.error
    };
  }

  return { statusCode: 0, body: null, statusMessage: null, headers: null, error: j?.error };
}

const base = items[0]?.json ?? items[0] ?? {};
const haResults = [];
let llmText = null;

for (const it of items) {
  const j = it.json ?? it;
  const kind = getKind(j);
  const resp = getHttpResponse(j);

  if (kind === 'ha') {
    const intent = getIntent(j);
    const status = resp.statusCode ?? 0;

    if (status >= 200 && status < 300) {
      haResults.push({ intent, success: true, status });
    } else {
      let error = 'unknown';
      if (status === 401) error = 'auth';
      else if (status === 404) error = 'notfound';
      else if (!status) error = 'network';

      const msg =
        resp?.error?.message ||
        (resp?.body ? (typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body)) : 'unknown');

      haResults.push({
        intent,
        success: false,
        status: status || 0,
        error,
        msg: error === 'auth' ? 'HA-Verbindung fehlgeschlagen, bitte Token prüfen.'
          : error === 'notfound' ? `Ich konnte ${intent?.entityId || intent?.domain} nicht finden.`
          : `Fehler bei ${intent?.entityId || intent?.domain}: ${msg}`
      });
    }
  }

  if (kind === 'ollama') {
    const status = resp.statusCode ?? 0;
    if (status >= 200 && status < 300) {
      llmText = resp?.body?.message?.content || resp?.body?.response || null;
    } else {
      const msg =
        resp?.error?.message ||
        (resp?.body ? (typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body)) : 'unknown');
      llmText = `Chat-Anfrage konnte nicht verarbeitet werden: ${msg}`;
    }
  }
}

// Build text
const haText = haResults.map(r => {
  if (!r.success) return r.msg;
  return `${entityLabel(r.intent)} ${actionText(r.intent?.service)}.`;
}).join(' ');

const confirmIntents = getConfirmIntents(base);
const confirmText = confirmIntents.length > 0
  ? `Für ${confirmIntents.map(i => i.entityId || i.domain).join(', ')} benötige ich noch deine Bestätigung.`
  : '';

const responseText = [haText, llmText, confirmText].filter(Boolean).join(' ') || 'Erledigt.';

return [{
  json: {
    // Keep original base if possible
    ...(base?.json ? base.json : base),
    haResults,
    llmText,
    responseText,
    __confirmationRequired: getConfirmationRequired(base),
  }
}];

// HA Fast - Assemble (for Merge By Position output)

const items = $input.all();

function actionText(service) {
  const svc = service || '';
  return svc.includes('turn_on') ? 'eingeschaltet'
    : svc.includes('turn_off') ? 'ausgeschaltet'
    : svc.includes('open') ? 'geöffnet'
    : svc.includes('close') ? 'geschlossen'
    : svc.includes('start') ? 'gestartet'
    : svc.includes('stop') ? 'gestoppt'
    : svc.includes('return') ? 'zurückgeschickt'
    : svc.includes('lock') ? 'gesperrt'
    : svc.includes('unlock') ? 'entsperrt'
    : svc.includes('arm') ? 'scharf geschaltet'
    : svc.includes('disarm') ? 'deaktiviert'
    : svc.includes('set_temperature') ? 'eingestellt'
    : 'ausgeführt';
}

function entityLabel(intent) {
  const raw = (intent?.entityId || intent?.domain || 'Aktion');
  const name = raw.split('.').pop().replace(/_/g, ' ');
  return name.charAt(0).toUpperCase() + name.slice(1);
}

function getKind(j) {
  return j?.__http?.kind || j?.input1?.__http?.kind || null;
}
function getIntent(j) {
  return j?.__intent || j?.input1?.__intent || null;
}
function getNeedsConfirmation(base) {
  return base?.__needsConfirmation || base?.input1?.__needsConfirmation || [];
}
function getConfirmationRequired(base) {
  return !!(base?.__confirmationRequired ?? base?.input1?.__confirmationRequired);
}
function getHttpResponse(j) {
  if (typeof j?.statusCode === 'number') return j;
  if (j?.input2 && typeof j.input2.statusCode === 'number') return j.input2;
  const maybe = Object.values(j || {}).find(v => v && typeof v === 'object' && typeof v.statusCode === 'number');
  return maybe || { statusCode: 0 };
}

const base = items[0]?.json ?? items[0] ?? {};
const haResults = [];

for (const it of items) {
  const j = it.json ?? it;
  const kind = getKind(j);
  const resp = getHttpResponse(j);

  if (kind !== 'ha') continue;

  const intent = getIntent(j);
  const status = resp.statusCode ?? 0;

  if (status >= 200 && status < 300) {
    haResults.push({ intent, success: true, status });
  } else {
    let error = 'unknown';
    if (status === 401) error = 'auth';
    else if (status === 404) error = 'notfound';
    else if (!status) error = 'network';

    const msg =
      resp?.error?.message ||
      (resp?.body ? (typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body)) : 'unknown');

    haResults.push({
      intent,
      success: false,
      status: status || 0,
      error,
      msg: error === 'auth' ? 'HA-Verbindung fehlgeschlagen, bitte Token prüfen.'
        : error === 'notfound' ? `Ich konnte ${intent?.entityId || intent?.domain} nicht finden.`
        : `Fehler bei ${intent?.entityId || intent?.domain}: ${msg}`
    });
  }
}

let responseText = haResults.map(r => {
  if (!r.success) return r.msg;
  return `${entityLabel(r.intent)} ${actionText(r.intent?.service)}.`;
}).join(' ');

const needs = getNeedsConfirmation(base);
if (getConfirmationRequired(base) && needs.length > 0) {
  responseText += ` Für ${needs.map(i => i.entityId || i.domain).join(', ')} benötige ich noch deine Bestätigung.`;
}

if (!responseText) responseText = 'Erledigt.';

return [{
  json: {
    ...(base?.json ? base.json : base),
    haResults,
    responseText,
    __confirmationRequired: getConfirmationRequired(base)
  }
}];

// Prepare session UPSERT: extract data before Postgres node
const sessionId = $json.sessionId;
const userId = $json.userId;
const title = ($json.userMessage || '').substring(0, 40);
return [{ json: { session_id: sessionId, user_id: userId, title } }];

// Restore Build Route Decision context after session UPSERT
// The UPSERT may have produced different $json; use named node reference to recover context.
return [{ json: $('Build Route Decision').first().json }];
